def _unique_slug(Legacy, base):
    slug = base[:200]
    if not Legacy.objects.filter(slug=slug).exists():
        return slug
    for i in range(2, 9999):
        c = f"{base[:196]}-{i}"
        if not Legacy.objects.filter(slug=c).exists():
            return c
    return base[:190]


def import_hrw(apps, schema_editor):
    Legacy = apps.get_model("legacies", "Legacy")
    Zone = apps.get_model("legacies", "Zone")
    HistoricalPeriod = apps.get_model("legacies", "HistoricalPeriod")
    HistoricalEvent = apps.get_model("legacies", "HistoricalEvent")
    Source = apps.get_model("legacies", "Source")

    zones = {z.slug: z for z in Zone.objects.all()}
    period = HistoricalPeriod.objects.filter(slug="protests-2014-2018").first()
    event = HistoricalEvent.objects.filter(slug="addis-ababa-master-plan-protests").first()
    existing = set(Legacy.objects.values_list("full_name", flat=True))
    now = timezone.now()

    created = 0
    for r in HRW_RECORDS:
        name = r["n"]
        if name in existing:
            continue
        zone = zones.get(r["z"]) or zones.get("shewa")
        if not zone:
            continue
        slug = _unique_slug(Legacy, slugify(name)[:200] or "hrw-record")
        legacy = Legacy(
            full_name=name,
            slug=slug,
            occupation=r.get("o", ""),
            relationship_to_person="Historical record / HRW source",
            zone=zone,
            story=r["s"],
            story_en=r["s"],
            original_language="en",
            category="civilian",
            historical_period=period,
            historical_event=event,
            death_year=r.get("dy"),
            place_of_death=r.get("pz", ""),
            verification_status="partial",
            notes="Imported from HRW Annex 1. Needs family/community verification before final publication.",
            status="APPROVED",
            approved_at=now,
        )
        legacy.save()
        Source.objects.create(
            legacy=legacy,
            source_type="hrw",
            title=HRW_SOURCE_TITLE,
            url=HRW_SOURCE_URL,
            publication_date="2016-06-15",
            excerpt=f'Listed in Annex 1. Location: {r.get("pz","")}',
        )
        existing.add(name)
        created += 1
    print(f"HRW migration: {created} records created.")


def remove_hrw(apps, schema_editor):
    Legacy = apps.get_model("legacies", "Legacy")
    names = [r["n"] for r in HRW_RECORDS]
    Legacy.objects.filter(full_name__in=names, notes__startswith="Imported from HRW").delete()


